import * as vscode from 'vscode';
import { isEntireBinary, resolveEntireBinary } from './entireBinaryResolver';
import { loadRewindIndex } from './checkpoints/rewindIndex';
import { runCommandAsync } from './runCommand';

/**
 * Shared dependencies injected into every Entire CLI command handler.
 *
 * Keeping these dependencies explicit (rather than captured via module-level
 * singletons) makes the commands independently testable and keeps
 * extension.ts responsible for wiring up the VS Code lifecycle objects.
 */
export interface EntireCommandContext {
	/** Output channel used for streaming command progress and results. */
	outputChannel: vscode.OutputChannel;
	/** Resolves the current repository path anchored to the active editor or workspace folder. */
	resolveRepoPath: () => Promise<string | undefined>;
	/** Refreshes the extension workspace probe after a command mutates repository state. */
	refreshWorkspace: (reason: string) => Promise<void>;
	/** Triggers a reload of the checkpoint and session tree views. */
	reloadTrees: () => void;
}

export const ENTIRE_AGENTS = ['claude-code', 'codex', 'gemini', 'opencode', 'factoryai-droid'] as const;
export type EntireAgent = typeof ENTIRE_AGENTS[number];

/**
 * Show the current CLI version via `entire version`.
 */
export async function showStatus(ctx: EntireCommandContext): Promise<void> {
	ctx.outputChannel.show(true);
	try {
		const resolved = await resolveEntireBinary();
		if (isEntireBinary(resolved)) {
			await vscode.window.showInformationMessage(resolved.raw);
		} else {
			await vscode.window.showErrorMessage(resolved.message);
		}
	} catch (error) {
		console.error(error);
		await vscode.window.showErrorMessage("Error getting status of entire cli. Make sure the cli is installed and try again");
	}
}

/**
 * Enable Entire in the current repository via `entire enable --agent <name>`.
 *
 * Presents a QuickPick for the agent name so the command runs non-interactively.
 */
export async function enableEntire(ctx: EntireCommandContext): Promise<void> {
	const repoPath = await ctx.resolveRepoPath();
	if (!repoPath) {
		await vscode.window.showWarningMessage("Open a repository folder to enable Entire.");
		return;
	}

	const agent = await vscode.window.showQuickPick([...ENTIRE_AGENTS], {
		placeHolder: 'Select an agent to enable',
		title: 'Enable Entire In Repository',
	});
	if (!agent) {
		return;
	}

	ctx.outputChannel.show(true);
	ctx.outputChannel.appendLine(`[enable] Running: entire enable --agent ${agent}`);
	const result = await runCommandAsync('entire', ['enable', '--agent', agent], repoPath);
	if (result.stdout) {
		ctx.outputChannel.appendLine(result.stdout.trim());
	}
	if (result.stderr) {
		ctx.outputChannel.appendLine(result.stderr.trim());
	}

	if (result.exitCode === 0) {
		await ctx.refreshWorkspace('entire enabled');
		await vscode.window.showInformationMessage(`Entire enabled for ${agent}.`);
	} else {
		const message = (result.stderr || result.stdout).trim();
		await vscode.window.showErrorMessage(`Failed to enable Entire: ${message}`);
	}
}

/**
 * Disable Entire in the current repository via `entire disable`.
 *
 * Prompts for confirmation before running. Existing session data is preserved.
 */
export async function disableEntire(ctx: EntireCommandContext): Promise<void> {
	const repoPath = await ctx.resolveRepoPath();
	if (!repoPath) {
		await vscode.window.showWarningMessage("Open a repository folder to disable Entire.");
		return;
	}

	const choice = await vscode.window.showWarningMessage(
		'Disable Entire in this repository? This stops session capture but preserves existing session data.',
		{ modal: true },
		'Disable',
	);
	if (choice !== 'Disable') {
		return;
	}

	ctx.outputChannel.show(true);
	ctx.outputChannel.appendLine('[disable] Running: entire disable');
	const result = await runCommandAsync('entire', ['disable'], repoPath);
	if (result.stdout) {
		ctx.outputChannel.appendLine(result.stdout.trim());
	}
	if (result.stderr) {
		ctx.outputChannel.appendLine(result.stderr.trim());
	}

	if (result.exitCode === 0) {
		await ctx.refreshWorkspace('entire disabled');
		await vscode.window.showInformationMessage('Entire disabled for this repository.');
	} else {
		const message = (result.stderr || result.stdout).trim();
		await vscode.window.showErrorMessage(`Failed to disable Entire: ${message}`);
	}
}

/**
 * Remove orphaned Entire data via `entire clean`.
 *
 * Runs a dry-run first and shows the preview in the output channel before
 * asking for confirmation to proceed.
 */
export async function cleanEntire(ctx: EntireCommandContext): Promise<void> {
	const repoPath = await ctx.resolveRepoPath();
	if (!repoPath) {
		await vscode.window.showWarningMessage("Open a repository folder to clean Entire state.");
		return;
	}

	ctx.outputChannel.show(true);
	ctx.outputChannel.appendLine('[clean] Running dry-run to preview changes...');
	const dryRunResult = await runCommandAsync('entire', ['clean', '--dry-run'], repoPath);
	const dryRunOutput = (dryRunResult.stdout || dryRunResult.stderr).trim();
	if (dryRunOutput) {
		ctx.outputChannel.appendLine(dryRunOutput);
	} else {
		ctx.outputChannel.appendLine('[clean] (nothing to clean)');
	}

	if (dryRunResult.exitCode !== 0) {
		await vscode.window.showErrorMessage(`Clean dry-run failed: ${dryRunOutput}`);
		return;
	}

	const choice = await vscode.window.showWarningMessage(
		'Proceed with cleaning orphaned Entire data? Check the output channel for details.',
		{ modal: true },
		'Clean',
	);
	if (choice !== 'Clean') {
		return;
	}

	ctx.outputChannel.appendLine('[clean] Running: entire clean');
	const result = await runCommandAsync('entire', ['clean'], repoPath);
	if (result.stdout) {
		ctx.outputChannel.appendLine(result.stdout.trim());
	}
	if (result.stderr) {
		ctx.outputChannel.appendLine(result.stderr.trim());
	}

	if (result.exitCode === 0) {
		await vscode.window.showInformationMessage('Entire state cleaned successfully.');
	} else {
		const message = (result.stderr || result.stdout).trim();
		await vscode.window.showErrorMessage(`Clean failed: ${message}`);
	}
}

/**
 * Delete the shadow branch and session state for the current commit via `entire reset --force`.
 *
 * Prompts with a destructive-action warning before running. Reloads the tree
 * views after a successful reset.
 */
export async function resetEntire(ctx: EntireCommandContext): Promise<void> {
	const repoPath = await ctx.resolveRepoPath();
	if (!repoPath) {
		await vscode.window.showWarningMessage("Open a repository folder to reset Entire session data.");
		return;
	}

	const choice = await vscode.window.showWarningMessage(
		'Reset Entire session data for the current commit? This deletes shadow branch and session state and cannot be recovered.',
		{ modal: true },
		'Reset',
	);
	if (choice !== 'Reset') {
		return;
	}

	ctx.outputChannel.show(true);
	ctx.outputChannel.appendLine('[reset] Running: entire reset --force');
	const result = await runCommandAsync('entire', ['reset', '--force'], repoPath);
	if (result.stdout) {
		ctx.outputChannel.appendLine(result.stdout.trim());
	}
	if (result.stderr) {
		ctx.outputChannel.appendLine(result.stderr.trim());
	}

	if (result.exitCode === 0) {
		await ctx.refreshWorkspace('entire reset');
		ctx.reloadTrees();
		await vscode.window.showInformationMessage('Entire session data reset successfully.');
	} else {
		const message = (result.stderr || result.stdout).trim();
		await vscode.window.showErrorMessage(`Reset failed: ${message}`);
	}
}

/**
 * Display hook performance traces via `entire trace`.
 *
 * Output is streamed to the output channel. Instructs the user to enable
 * DEBUG logging if no trace data is present.
 */
export async function showTrace(ctx: EntireCommandContext): Promise<void> {
	const repoPath = await ctx.resolveRepoPath();
	if (!repoPath) {
		await vscode.window.showWarningMessage("Open a repository folder to show Entire traces.");
		return;
	}

	ctx.outputChannel.show(true);
	ctx.outputChannel.appendLine('[trace] Running: entire trace');
	const result = await runCommandAsync('entire', ['trace'], repoPath);

	if (result.stdout) {
		ctx.outputChannel.appendLine(result.stdout.trim());
	}
	if (result.stderr) {
		ctx.outputChannel.appendLine(result.stderr.trim());
	}

	if (result.exitCode !== 0) {
		const message = (result.stderr || result.stdout).trim();
		await vscode.window.showWarningMessage(`Trace unavailable: ${message || 'Run with ENTIRE_LOG_LEVEL=DEBUG to enable traces.'}`);
	} else if (!result.stdout.trim()) {
		ctx.outputChannel.appendLine('[trace] No trace data available. Run with ENTIRE_LOG_LEVEL=DEBUG to enable traces.');
	}
}

/**
 * Configure Entire and manage agent hooks via `entire configure`.
 *
 * Opens an integrated terminal because `entire configure` is interactive on
 * first run and when adding new agents.
 */
export async function configureEntire(ctx: EntireCommandContext): Promise<void> {
	const repoPath = await ctx.resolveRepoPath();
	const terminal = vscode.window.createTerminal({
		name: 'Entire: Configure',
		cwd: repoPath,
	});
	terminal.show();
	terminal.sendText('entire configure');
}

/**
 * Scan for stuck or problematic sessions via `entire doctor`.
 *
 * Opens an integrated terminal because `entire doctor` is interactive — it
 * prompts to condense, discard, or skip each stuck session.
 */
export async function runDoctor(ctx: EntireCommandContext): Promise<void> {
	const repoPath = await ctx.resolveRepoPath();
	const terminal = vscode.window.createTerminal({
		name: 'Entire: Doctor',
		cwd: repoPath,
	});
	terminal.show();
	terminal.sendText('entire doctor');
}

/**
 * Resume an agent session from a local branch via `entire resume <branch>`.
 *
 * Presents a QuickPick populated from local Git branches, then opens an
 * integrated terminal because `entire resume` may prompt for confirmation.
 */
export async function resumeSession(ctx: EntireCommandContext): Promise<void> {
	const repoPath = await ctx.resolveRepoPath();
	if (!repoPath) {
		await vscode.window.showWarningMessage("Open a repository folder to resume an Entire session.");
		return;
	}

	const branchResult = await runCommandAsync('git', ['branch', '--format=%(refname:short)'], repoPath);
	if (branchResult.exitCode !== 0) {
		await vscode.window.showErrorMessage(`Could not list branches: ${branchResult.stderr.trim()}`);
		return;
	}

	const branches = branchResult.stdout.split('\n').map(b => b.trim()).filter(Boolean);
	if (branches.length === 0) {
		await vscode.window.showWarningMessage("No local branches found.");
		return;
	}

	const branch = await vscode.window.showQuickPick(branches, {
		placeHolder: 'Select a branch to resume the agent session from',
		title: 'Resume Entire Session',
	});
	if (!branch) {
		return;
	}

	const terminal = vscode.window.createTerminal({
		name: 'Entire: Resume',
		cwd: repoPath,
	});
	terminal.show();
	terminal.sendText(`entire resume ${branch}`);
}

/**
 * Rewind to a previous checkpoint via `entire rewind --to <commit>`.
 *
 * Loads available rewind points via `entire rewind --list` and presents them
 * in a QuickPick. After the user selects a point and confirms the destructive
 * warning, runs the rewind in an integrated terminal.
 */
export async function rewindSession(ctx: EntireCommandContext): Promise<void> {
	const repoPath = await ctx.resolveRepoPath();
	if (!repoPath) {
		await vscode.window.showWarningMessage("Open a repository folder to rewind an Entire session.");
		return;
	}

	ctx.outputChannel.appendLine('[rewind] Loading rewind points...');
	const index = await loadRewindIndex(repoPath);

	if (index.error) {
		ctx.outputChannel.appendLine(`[rewind] ${index.error}`);
		await vscode.window.showWarningMessage(`Could not load rewind points: ${index.error}`);
		return;
	}

	if (index.points.length === 0) {
		await vscode.window.showInformationMessage("No rewind points available for the current session.");
		return;
	}

	const items = index.points.map(rp => ({
		label: rp.displayHash,
		description: rp.message.length > 80 ? `${rp.message.slice(0, 80)}…` : rp.message,
		detail: [rp.date, rp.sessionPrompt ? `Prompt: ${rp.sessionPrompt.slice(0, 60)}` : undefined]
			.filter(Boolean)
			.join(' · '),
		pointId: rp.pointId,
	}));

	const selected = await vscode.window.showQuickPick(items, {
		placeHolder: 'Select a checkpoint to rewind to',
		title: 'Rewind Entire Session',
		matchOnDescription: true,
		matchOnDetail: true,
	});
	if (!selected) {
		return;
	}

	const choice = await vscode.window.showWarningMessage(
		`Rewind to ${selected.label}? Changes made after this checkpoint will be discarded.`,
		{ modal: true },
		'Rewind',
	);
	if (choice !== 'Rewind') {
		return;
	}

	const terminal = vscode.window.createTerminal({
		name: 'Entire: Rewind',
		cwd: repoPath,
	});
	terminal.show();
	terminal.sendText(`entire rewind --to ${selected.pointId}`);
}

/**
 * Generate a short AI-powered explanation of the current session via `entire explain -s`.
 *
 * Output is streamed to the output channel.
 */
export async function explainSession(ctx: EntireCommandContext): Promise<void> {
	const repoPath = await ctx.resolveRepoPath();
	if (!repoPath) {
		await vscode.window.showWarningMessage("Open a repository folder to explain an Entire session.");
		return;
	}

	ctx.outputChannel.show(true);
	ctx.outputChannel.appendLine('[explain] Running: entire explain -s');
	const result = await runCommandAsync('entire', ['explain', '-s'], repoPath);

	if (result.stdout) {
		ctx.outputChannel.appendLine(result.stdout.trim());
	}
	if (result.stderr) {
		ctx.outputChannel.appendLine(result.stderr.trim());
	}

	if (result.exitCode !== 0) {
		const message = (result.stderr || result.stdout).trim();
		await vscode.window.showWarningMessage(`Could not explain session: ${message}`);
	}
}

