 			watcher,
 			watcher.onDidCreate(() => scheduleProbeRefresh(reason)),
 			watcher.onDidChange(() => scheduleProbeRefresh(reason)),
 			watcher.onDidDelete(() => scheduleProbeRefresh(reason)),
